#include<bits/stdc++.h>
using namespace std;
struct node{
    double a,b;
}a[4];
bool cmp(node a,node b){
    return a.a<b.a;
}
int main(){
    double aa,b,c,n,t,m;
    cin>>n>>t>>m>>aa>>b>>c;
    a[1].a=n/aa;
    a[1].b=1;
    a[2].a=n/b+t;
    a[2].b=2;
    a[3].a=m/aa+(n+m)/c;
    a[3].b=3;
    sort(a+1,a+4,cmp);
    cout<<"MODE ";
    for(int i=1;i<=a[1].b;i++) cout<<"I";
    printf("\n%.2lf",a[1].a);
    return 0;
}
